options.helpers:
// Header status class based on active alarms
context.handlebars.registerHelper('headerStatusClass', function(hasAlarm) {
  return hasAlarm ? 'device-header__status--critical' : 'device-header__status--generating';
});

// Header status label
context.handlebars.registerHelper('headerStatusLabel', function(hasAlarm) {
  return hasAlarm ? 'Critical' : 'Normal';
});

options.afterRender:
const apiEndpoint = context.grafana.replaceVariables('${api_endpoint}');
const commandToken = context.grafana.replaceVariables('${command_token}');
const deviceTypes = {1: 'inverter', 2: 'relay', 3: 'logger'};

context.element.querySelectorAll('.unifilar__ctrl-btn').forEach(btn => {
  if (btn.dataset.listenerAdded) return;
  btn.dataset.listenerAdded = 'true';

  btn.addEventListener('click', (e) => {
    e.stopPropagation();

    const userRole = (window.grafanaBootData && window.grafanaBootData.user) ? window.grafanaBootData.user.orgRole : '';
    if (userRole !== 'Admin') {
      alert('Access denied. This command is only available for Admin users.');
      return;
    }

    const action = btn.dataset.action;
    const deviceId = btn.dataset.deviceId;
    const deviceTypeId = parseInt(btn.dataset.deviceTypeId);
    const deviceType = deviceTypes[deviceTypeId] || 'unknown';
    const actionLabel = action === 'ligar' ? 'Turn ON' : action === 'desligar' ? 'Turn OFF' : 'Reset';

    if (!confirm(actionLabel + ' this ' + deviceType + '?')) return;

    const userName = window.grafanaBootData.user.name || 'Unknown';
    const endpoint = action === 'reset' ? apiEndpoint + '/commands/' + deviceId + '/relay/reset' : apiEndpoint + '/commands/' + deviceId + '/' + deviceType + '/' + action;

    fetch(endpoint, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'X-Command-Token': commandToken
      },
      body: JSON.stringify({ username: userName, device_id: deviceId, timestamp: new Date().toISOString() })
    })
    .then(r => { if (r.ok) { location.reload(); } else { alert('Failed. Status: ' + r.status); } })
    .catch(e => { alert('Error: ' + e.message); });
  });
});

// Power Control - Inverter only
context.element.querySelectorAll('.unifilar__power-btn').forEach(btn => {
  if (btn.dataset.listenerAdded) return;
  btn.dataset.listenerAdded = 'true';

  btn.addEventListener('click', (e) => {
    e.stopPropagation();

    const userRole = (window.grafanaBootData && window.grafanaBootData.user) ? window.grafanaBootData.user.orgRole : '';
    if (userRole !== 'Admin') {
      alert('Access denied. This command is only available for Admin users.');
      return;
    }

    const deviceId = btn.dataset.deviceId;
    const deviceTypeId = parseInt(btn.dataset.deviceTypeId);
    const deviceTypeLabel = deviceTypeId === 3 ? 'logger' : 'inverter';
    const input = context.element.querySelector('.unifilar__power-input');
    const powerValue = parseFloat(input.value);

    if (isNaN(powerValue) || powerValue <= 0) {
      alert('Please enter a valid power value greater than 0.');
      return;
    }

    if (!confirm('Set power to ' + powerValue + ' for this ' + deviceTypeLabel + '?')) return;

    fetch(apiEndpoint + '/commands/' + deviceId + '/' + deviceTypeLabel + '/potencia', {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'X-Command-Token': commandToken
      },
      body: JSON.stringify({ power: powerValue })
    })
    .then(r => { if (r.ok) { alert('Power set successfully!'); input.value = ''; } else { alert('Failed. Status: ' + r.status); } })
    .catch(e => { alert('Error: ' + e.message); });
  });
});

options.helpers:
// Status class based on active alarms
context.handlebars.registerHelper('statusClass', function(hasAlarm) {
  return hasAlarm ? 'unifilar__status--critical' : 'unifilar__status--ok';
});

// Status label based on active alarms
context.handlebars.registerHelper('statusLabel', function(hasAlarm) {
  return hasAlarm ? 'CRITICAL' : 'NORMAL';
});

// String class based on current
context.handlebars.registerHelper('stringClass', function(current) {
  return current >= 1 ? 'unifilar__string--ok' : 'unifilar__string--fault';
});

// Count OK strings
context.handlebars.registerHelper('countOk', function(data) {
  return data.filter(d => d.string_current >= 1).length;
});

// Count fault strings
context.handlebars.registerHelper('countFault', function(data) {
  return data.filter(d => d.string_current < 1).length;
});

// Check if device is inverter (device_type_id = 1)
context.handlebars.registerHelper('isInverter', function(deviceTypeId) {
  return deviceTypeId === 1;
});

// Check if device is relay (device_type_id = 2)
context.handlebars.registerHelper('isRelay', function(deviceTypeId) {
  return deviceTypeId === 2;
});

// Check if device is logger (device_type_id = 3)
context.handlebars.registerHelper('isLogger', function(deviceTypeId) {
  return deviceTypeId === 3;
});

// Check if device is inverter or logger (for power control)
context.handlebars.registerHelper('isInverterOrLogger', function(deviceTypeId) {
  return deviceTypeId === 1 || deviceTypeId === 3;
});

// Count associated inverters for logger
context.handlebars.registerHelper('countInverters', function(data) {
  return data.filter(d => d.associated_inverter_id != null).length;
});
